mapper.select:
select id, dict_type, dict_label, dict_value, sort_no, education_scopes from sys_dict_item where dict_type = #{dictType} and enabled = 1
and (dict_label like concat('%', #{keyword}, '%') or dict_value like concat('%', #{keyword}, '%'))
order by sort_no, id limit #{offset}, #{limit}

mapper.update:
update sys_dict_item
set dict_label = #{dictLabel},
    dict_value = #{dictValue},
    education_scopes = #{educationScopes}
where id = #{id}
